import ast
import subprocess
import sys
import json

REPO = "/home/polaris/wt/phase3a"


def strip_docstrings(source):
    tree = ast.parse(source)

    def clean(node):
        # Remove docstring: first stmt if Expr(Constant str) in module/class/func bodies
        if isinstance(node, (ast.Module, ast.ClassDef, ast.FunctionDef, ast.AsyncFunctionDef)):
            body = node.body
            if body and isinstance(body[0], ast.Expr) and isinstance(
                getattr(body[0], "value", None), ast.Constant
            ) and isinstance(body[0].value.value, str):
                node.body = body[1:]
                # guard against emptied body
                if not node.body:
                    node.body = [ast.Pass()]
        for child in ast.iter_child_nodes(node):
            clean(child)

    clean(tree)
    return ast.unparse(ast.fix_missing_locations(tree))


def git_head_version(path):
    return subprocess.run(
        ["git", "-C", REPO, "show", f"HEAD:{path}"],
        capture_output=True, text=True, check=True
    ).stdout


def main():
    changed = subprocess.run(
        ["git", "-C", REPO, "diff", "--name-only", "HEAD", "--", "*.py"],
        capture_output=True, text=True, check=True
    ).stdout.split()

    passes = []
    failures = []
    errors = []
    for path in changed:
        try:
            head_src = git_head_version(path)
            with open(f"{REPO}/{path}") as f:
                work_src = f.read()
            head_stripped = strip_docstrings(head_src)
            work_stripped = strip_docstrings(work_src)
            if head_stripped == work_stripped:
                passes.append(path)
            else:
                failures.append(path)
        except Exception as e:
            errors.append((path, repr(e)))

    print(json.dumps({
        "total": len(changed),
        "passes": len(passes),
        "pass_files": passes,
        "failures": failures,
        "errors": errors,
    }, indent=2))
    if failures or errors:
        sys.exit(1)


if __name__ == "__main__":
    main()
